                {'id': 4, 'name': 'guest',          'role': 'user',  'active': False}
            ]
        }
        self.text = _json.dumps(_data)
        self._data = _data
    def json(self):
        return self._data
class _Requests:
    def get(self, url, **kw):
        return _Response(url)
    def post(self, url, **kw):
